            ContentJson = """{"title":"Part-Number List Import","groups":[{"heading":"Where to import","items":[{"label":"Open the list","value":"Admin > EDI > Trading Partners tab > the part-number button on the partner's row."},{"label":"Import CSV button","value":"In the list's toolbar, next to Add Row. Opens a file picker for a .csv or .txt file."},{"label":"Per-partner","value":"The import only affects the partner whose list is open. Each partner has its own list."}]},{"heading":"File format","items":[{"label":"Two columns","value":"Column 1 is the partner's part number. Column 2 is your part number."},{"label":"Header row required","value":"The first row must be a header. A file with only data rows and no header imports nothing."},{"label":"Encoding","value":"A plain spreadsheet file. Text wrapped in quotes is fine."},{"label":"Blank lines","value":"Completely blank rows are ignored."}]},{"heading":"Accepted column headers","items":[{"label":"Partner column","value":"A heading that contains 'partner', 'their', or 'customer'. For example 'Partner Part #', 'Their Number', or 'Customer Item'."},{"label":"Our column","value":"A heading that contains 'our', 'forge', or 'internal'. For example 'Our Part #' or 'Internal Number'."},{"label":"If headings aren't recognized","value":"The import falls back to order: the first column is the partner's, the second is yours. You still need a header row."}]},{"heading":"How rows merge","items":[{"label":"Merge by partner number","value":"If a partner number is already in the list, its matching number is updated; if it's new, the pair is added. Re-importing a corrected file won't create duplicates."},{"label":"Trimming","value":"Extra spaces before or after each number are removed."},{"label":"Upper and lower case","value":"Partner numbers match regardless of case, so 'ABC' and 'abc' count as the same one (the last wins)."},{"label":"Empty cells skipped","value":"A row missing either number is skipped and counted under Skipped."}]},{"heading":"Result counts (shown after import)","items":[{"label":"Imported","value":"New pairs added to the list."},{"label":"Updated","value":"Existing pairs whose matching number was changed."},{"label":"Skipped","value":"Rows skipped because a number was blank."},{"label":"Unresolved","value":"How many rows point at a part number that isn't in your catalog yet — worth fixing before orders come in."},{"label":"Total Rows","value":"How many pairs are in the list once the import finishes."}]},{"heading":"Example file","items":[{"label":"Header","value":"PartnerPartNumber,OurPartNumber"},{"label":"Row 1","value":"AC-1000,WIDGET-001"},{"label":"Row 2","value":"AC-1001,WIDGET-002"},{"label":"Result","value":"Two new pairs are added. If WIDGET-002 isn't in your catalog yet, Unresolved shows 1 and that row is flagged 'No matching part'."}]}]}"""
